// تحسينات لإدخال البيانات
(function() {
    // تحسين حقل إدخال username
    var usernameInput = document.querySelector('input[username-field]');
    if(usernameInput) {
        // منع المسافات البيضاء
        usernameInput.addEventListener('input', function(e) {
            if(hotspotConfig['input-rm-white-spaces'] === 1) {
                this.value = this.value.replace(/\s/g, '');
            }
            if(hotspotConfig['input-to-lower'] === 1) {
                this.value = this.value.toLowerCase();
            }
            if(hotspotConfig['input-to-upper'] === 1) {
                this.value = this.value.toUpperCase();
            }
            if(hotspotConfig['input-only-numbers'] === 1) {
                this.value = this.value.replace(/[^0-9]/g, '');
            }
            if(hotspotConfig['input-no-numbers'] === 1) {
                this.value = this.value.replace(/[0-9]/g, '');
            }
            if(hotspotConfig['input-only-alphanumeric'] === 1) {
                this.value = this.value.replace(/[^a-zA-Z0-9]/g, '');
            }
        });
        
        // تعيين نوع الإدخال
        if(hotspotConfig['input-type']) {
            usernameInput.setAttribute('type', hotspotConfig['input-type']);
        }
        if(hotspotConfig['input-autocomplete']) {
            usernameInput.setAttribute('autocomplete', hotspotConfig['input-autocomplete']);
        }
    }
    
    // تحسين حقل إدخال password
    var passwordInput = document.querySelector('input[password-field]');
    if(passwordInput) {
        passwordInput.addEventListener('input', function(e) {
            if(hotspotConfig['input-rm-white-spaces'] === 1) {
                this.value = this.value.replace(/\s/g, '');
            }
        });
    }
})();